    <script>
        $(document).ready(function () {
            const txtSoTien = $('#txtSoTien');
            const hiddenSoTien = $('#hiddenSoTien');
             
            function formatCurrency(input) { 
                let rawValue = input.val().replace(/[^0-9]/g, '');
                 
                if (!rawValue) rawValue = '0';                 
                let intValue = parseInt(rawValue, 10);
                hiddenSoTien.val(intValue);
                input.val(intValue.toLocaleString('vi-VN'));
            }

            txtSoTien.on('input', function () {
                formatCurrency($(this));
            });

            txtSoTien.on('focus', function () {
                if ($(this).val() === '0') {
                    $(this).val('');
                }
            });

            txtSoTien.on('blur', function () {
                if ($(this).val() === '') {
                    $(this).val('0');
                    hiddenSoTien.val('0');
              ");
